INSERT INTO places_fts VALUES ('poi-zhao-bastille', 'La Taverne de Zhao', 'restaurant', 'asiatique français', '67 rue de la Roquette, 75011 Paris, France', '', 'En plein cœur de la rue de la Roquette, cette taverne capte toute l’énergie électrique du quartier. Plus vibrante que ses sœurs, elle est le point de ralliement des amateurs de saveurs percutantes. Les Biang Biang y sont servies avec un rythme effréné dans un décor urbain qui colle à l''esprit nocturne de Bastille.');
